1	export interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	export interface QuoteInput {
8	  items: QuoteItem[];
9	  customer: { yearsWithMHPCO: number };
10	  isFollowUp: boolean;
11	}
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	const BLOCK_OF_3_PREMIUM = 60;
16	const CURSED_SURCHARGE_RATE = 0.5;
17	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const LOYALTY_THRESHOLD_YEARS = 2;
20	
21	const BASE_PREMIUM: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	export function quote(input: QuoteInput): number {
31	  let policyBase = 0;
32	
33	  const itemTypeCounts: Record<string, number> = {};
34	  for (const item of input.items) {
35	    itemTypeCounts[item.type] = (itemTypeCounts[item.type] || 0) + 1;
36	  }
37	
38	  for (const [type, count] of Object.entries(itemTypeCounts)) {
39	    if (count === 3) {
40	      policyBase += BLOCK_OF_3_PREMIUM;
41	    } else {
42	      policyBase += count * BASE_PREMIUM[type];
43	    }
44	  }
45	
46	  let itemSurcharges = 0;
47	  for (const item of input.items) {
48	    const itemBase = BASE_PREMIUM[item.type];
49	    if (item.cursed) {
50	      itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
51	    }
52	    if (item.enchantment !== undefined && item.enchantment >= 5) {
53	      itemSurcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
54	    }
55	  }
56	
57	  const loyaltyDiscount = input.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
58	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
59	  const policyPremium = policyBase + itemSurcharges - loyaltyDiscount + firstInsuranceSurcharge;
60	  return Math.ceil(policyPremium + PROCESSING_FEE);
61	}
